    scwin.MSG_CM_ERR_002 = "변경된 사항이 없습니다."
    scwin.MSG_CM_ERR_003 = "조회된 데이터가 없습니다."
    scwin.MSG_CM_ERR_004 = "사용자별 권한이 존재합니다. 삭제 후 복사하세요."
    scwin.MSG_CM_ERR_005 = "사용자를 먼저 조회하세요."
    scwin.MSG_CM_ERR_006 = "프로그램 조회후 사용하세요."

    scwin.retrieveYn = "N";

    // var ENABLE_BGCOLOR = "#FFFFFF";
    // var DISABLE_BGCOLOR = "#F3F3F3";

    if ("05" != "") {
        // lc_userClsCd_param.setValue(05) = lc_userClsCd_param.IndexOfColumn("code", "05");
        lc_userClsCd_param.setSelectedIndex(5);
        $c.gus.cfDisableBtn([lc_userClsCd_param]);
    } else {
        lc_userClsCd_param.setValue(0);
    }


    if ("DS61" != "") {
        // lux_privGroup.Index = lux_privGroup.IndexOfColumn("code", "DS61");
        lux_privGroup.setValue("DS61");
        $c.gus.cfDisableBtn([lux_privGroup]);
    }

    txt_searchUser.focus();
    //cfDisableBtn([b_Save,b_UndoAll,b_DeleteAll,b_Filter]);
    $c.gus.cfDisableBtn([b_DeleteAll, b_Filter]); // b_UndoAll
};

