//-------------------------------------------------------------------------
// function name : f_DsSearch
// function desc : 필터
//-------------------------------------------------------------------------

scwin.f_Filter = function () {

    debugger
    var pgmCond = lux_pgmCond.getValue();
    var pgmName = txt_pgmName.getValue();

    var rcolumnId = "pgmNm";
    switch (pgmCond) {
        case "1":
            rcolumnId = "pgmNm";
            break;
        case "2":
            rcolumnId = "pgmId";
            break;
    }

    ds_412List.removeColumnFilterAll();
    if (pgmCond > 0) {
        $c.data.dataListFilter(ds_412List, "LIKE", true,
            {
                colId: rcolumnId, func: function (cellData, tmpParam, rowIdx) {
                    debugger
                    if (cellData.indexOf(pgmName) > -1) {
                        return true;
                    }
                    return false;   // return이 true인 경우 적용하고 false인 경우 넘김
                }
            });
    } else {
        // ds_412List.removeColumnFilterAll();
    }

    // ds_412List.UseFilter = true;
    // ds_412List.Filter();

    /**************
     * 2006.4.16 이진욱 수정
     * 내용: 조회시 사용자가 여러명일경우 각각에 대해서 필터링이 되는 경우를 막기위해서
     *      필터링 이후 자동 필터 안되도록 필터링 옵션을 false로 바꾼다.
     **************/
    // ds_412List.UseFilter = false;

}

