//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function (idx) {

    var vSysCd = "";
    var vSearchCond = "";
    var vSearchContent = "";
    var vCondition = "?";
    var vDataSet = "";
    var vDataId = "";
    var vUserId = "";
    var vDeptPrivYn = "";


    if (idx == "1") {
        // 프로그램 조회
        vDataSet = "ds_411List";
        vSysCd = lux_sysCd.getValue();
        vDeptPrivChk = deptPrivChk.getValue();

        if (vDeptPrivChk) {
            vDeptPrivYn = "1";
        }

        if (vSysCd.trim() == "") {
            $c.win.alert("시스템구분은 필수선택사항입니다.");
            lux_sysCd.focus();
            return false
        }

        vSearchCond = lux_programSearch.getValue();
        vSearchContent = txt_searchProgram.getValue();
        vUserId = ds_315List.getCellData(ds_315List.rowPosition, "userId");

        vCondition += "sysCls=" + vSysCd +
            "&programLupCond=" + vSearchCond +
            "&qryCntn=" + vSearchContent +
            "&userId=" + vUserId +
            "&deptPrivYn=" + vDeptPrivYn +
            "&useYn=1";
        // ds_411List.DataId = "/cm.bc.comnmgnt.programmgnt.RetrieveUserEachPrivilegeExceptProgramListCMD.do" + vCondition;

        sbm_411List.action = "/cm.bc.comnmgnt.programmgnt.RetrieveUserEachPrivilegeExceptProgramListCMD.do" + vCondition
        $c.sbm.execute(sbm_411List); // ds_411List.Reset();

    } else {

        // 사용자 조회 
        vSearchCond = lux_userSearch.getValue();;
        vSearchContent = txt_searchUser.getValue();
        var vUserClsCd = lc_userClsCd_param.getValue();

        dma_retrieve.setEmptyValue();
        if (vSearchCond == "0") {
            dma_retrieve.set("userNm", vSearchContent)
        } else {
            dma_retrieve.set("userId", vSearchContent)
        }
        dma_retrieve.set("userClsCd", vUserClsCd)

        scwin.retrieveYn = "N";
        // tr_315List.Action = "/cm.bc.comnmgnt.usermgnt.cmd.RetrieveUserListCMD.do" + vCondition
        // tr_315List.Post();
        sbm_315List.action = "/cm.bc.comnmgnt.usermgnt.cmd.RetrieveUserListCMD.do" + vCondition

        $c.sbm.execute(sbm_315List); // tr_315List.Post();

    }

}
//-------------------------------------------------------------------------
// function name : f_MainRetrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_MainRetrieve = async function (userId) {
    var condition = "?userId=" + userId;
    // tr_userEachScreenPriv.Action = "/cm.bc.comnmgnt.privmgnt.RetrieveUserEachScreenPrivilegeListCMD.do" + condition;
    // tr_userEachScreenPriv.Post();
    sbm_userEachScreenPriv.action = "/cm.bc.comnmgnt.privmgnt.RetrieveUserEachScreenPrivilegeListCMD.do" + condition
    await $c.sbm.execute(sbm_userEachScreenPriv); // tr_userEachScreenPriv.Post();

}

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------

scwin.f_Save = async function () {
    //변경한 데이터가 있는지 체크한다. 
    if (ds_412List.getModifiedIndex().length == 0 &&
        ds_tplPrivilege.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(scwin.MSG_CM_ERR_002);
        return;
    };

    let confirmMessage = await $c.win.confirm(scwin.MSG_CM_CRM_001)
    if (confirmMessage) {
        $c.sbm.execute(sbm_save); // tr_save.Post();
    }

}

//-------------------------------------------------------------------------
// function name : f_LMove
// function desc : 좌이동
//-------------------------------------------------------------------------

scwin.f_LMove = function () {
    //cfProgressWinOpen();  
    var pgmCnt = ds_411List.getTotalRow();
    var privCnt = ds_412List.getTotalRow();
    var userCnt = ds_315List.getTotalRow();
    var userId = ds_315List.getCellData(ds_315List.rowPosition, "userId");

    if (userCnt < 1) {
        $c.win.alert("프로그램을 추가할 사용자를 조회해주십시오.");
        txt_searchUser.focus();
        return false;
    }

    if (pgmCnt < 1) {
        //cfProgressWinClose();
        $c.win.alert(scwin.MSG_CM_ERR_006);
        return;
    } else {
        // gr_412List.ColumnProp("qryYn", "HeadCheck") = true; // TO-DO

        for (var i = pgmCnt; i >= 0; i--) {
            var chkYn = ds_411List.getCellData(i, "chk");
            var pgmId = ds_411List.getCellData(i, "pgmId");
            var pgmNm = ds_411List.getCellData(i, "pgmNm");
            var deptPrivYn = ds_411List.getCellData(i, "deptPrivYn");

            var ds_411RowStatus = ds_411List.getRowStatusValue(i);
            if (chkYn == "T") {
                if (ds_411RowStatus == "1") {
                    // 로우상태가 Normal이 아닌 경우

                    for (var k = 0; k < privCnt; k++) {
                        var privPgmId = ds_412List.getCellData(k, "pgmId");
                        if (pgmId == privPgmId) {
                            ds_412List.setCellData(k, "chk", "F");
                            $c.data.undoRow(ds_412List, "Y"); // ds_412List.Undo(k);

                        } else {
                            continue;
                        }
                    }

                } else if (ds_411RowStatus == "3") {

                    // 로우상태가 Normal인 경우
                    var addFlag = "A";
                    for (var j = 0; j < privCnt; j++) {
                        var userPgmId = ds_412List.getCellData(j, "pgmId");
                        if (pgmId == userPgmId) {
                            addFlag = "N";
                            break;
                        } else {
                            continue;
                        }
                    }


                    if (addFlag == "A") {
                        // ds_412List.addRow();
                        ds_412List.insertRow();
                        ds_412List.setCellData(ds_412List.rowPosition, "userId", userId);
                        ds_412List.setCellData(ds_412List.rowPosition, "pgmId", pgmId);
                        ds_412List.setCellData(ds_412List.rowPosition, "pgmNm", pgmNm);
                        ds_412List.setCellData(ds_412List.rowPosition, "insYn", 0);
                        ds_412List.setCellData(ds_412List.rowPosition, "qryYn", 1);
                        ds_412List.setCellData(ds_412List.rowPosition, "modYn", 0);
                        ds_412List.setCellData(ds_412List.rowPosition, "delYn", 0);
                        ds_412List.setCellData(ds_412List.rowPosition, "prtnYn", 0);
                        ds_412List.setCellData(ds_412List.rowPosition, "xlsDwnldYn", 0);
                        ds_412List.setCellData(ds_412List.rowPosition, "deptPrivYn", deptPrivYn);
                        ds_412List.setCellData(ds_412List.rowPosition, "chk", "F");
                    }

                }

            } // IF 1

        } // End For
        for (var i = pgmCnt; i >= 0; i--) {
            var chkYn = ds_411List.getCellData(i, "chk");
            if (chkYn == "T") {
                ds_411List.deleteRow(i); // ds_411List.DeleteRow(i);
                ds_411List.removeRow(i);
            }
        }
    }

    if (ds_412List.getTotalRow() > 0) {
        // 에러나서 일단 주석
        // $c.gus.cfEnableBtnOnly([b_Save, b_UndoAll, b_DeleteAll, b_Filter]);
        b_Save.setDisabled(false);
        b_UndoAll.setDisabled(false);
        b_DeleteAll.setDisabled(false);
        b_Filter.setDisabled(false);
    }

    scwin.f_GridColHeaderCheckChange('gr_411List');
}

//-------------------------------------------------------------------------
// function name : f_RMove
// function desc : 우이동
//-------------------------------------------------------------------------
scwin.f_RMove = function () {
    //cfProgressWinOpen();
    var pgmCnt = ds_411List.getTotalRow();
    var privCnt = ds_412List.getTotalRow();

    if (privCnt < 0) {
        $c.gus.cfProgressWinClose();
        $c.win.alert(scwin.MSG_CM_ERR_005);
        return;
    } else {

        for (var i = privCnt - 1; i >= 0; i--) {
            var chkYn = ds_412List.getCellData(i, "chk");
            var pgmId = ds_412List.getCellData(i, "pgmId");
            var pgmNm = ds_412List.getCellData(i, "pgmNm");
            var deptPrivYn = ds_412List.getCellData(i, "deptPrivYn");

            var rowStatus = ds_412List.getRowStatusValue(i);

            if (chkYn == "T") {
                var addFlag = "A";
                for (var j = 0; j < pgmCnt; j++) {
                    var userPgmId = ds_411List.getCellData(j, "pgmId");
                    if (pgmId == userPgmId) {
                        addFlag = "N";
                    }
                }
                if (addFlag == "A") {
                    ds_411List.insertRow();
                    // ds_411List.focu
                    // 추가한 코드
                    let rowIndex = ds_411List.getTotalRow() - 1
                    gr_411List.setFocusedCell(rowIndex, "pgmId", true);
                    let focusedIdx = gr_411List.getFocusedRowIndex()
                    ds_411List.setCellData(focusedIdx, "pgmId", pgmId); // ds_411List.rowPosition -> j
                    ds_411List.setCellData(focusedIdx, "pgmNm", pgmNm);
                    ds_411List.setCellData(focusedIdx, "chk", "F");
                    ds_411List.setCellData(focusedIdx, "side", "R");
                    ds_411List.setCellData(focusedIdx, "deptPrivYn", deptPrivYn);
                    ds_411List.modifyAllStatus("R"); // ds_411List.ResetStatus()
                }
                ds_412List.deleteRow(i) //  ds_412List.DeleteRow(i);
            }
        }

        for (var i = privCnt; i >= 0; i--) {
            var chkYn = ds_412List.getCellData(i, "chk");
            if (chkYn == "T" && rowStatus == "1") {
                ds_412List.deleteRow(i) //  ds_412List.DeleteRow(i);
            }
        }
    }
    if (ds_412List.getTotalRow() > 0) {
        // $c.gus.cfEnableBtnOnly([b_Save, b_UndoAll, b_DeleteAll, b_Filter]);
        b_Save.setDisabled(false);
        b_UndoAll.setDisabled(false);
        b_DeleteAll.setDisabled(false);
        b_Filter.setDisabled(false);
    }
    scwin.f_GridColHeaderCheckChange('gr_412List');
}




//-------------------------------------------------------------------------
// function name : f_copyPrivlege()
// function desc : 그룹복사
//-------------------------------------------------------------------------

scwin.f_copyPrivlege = async function (pType) {
    var vUserId = "";   // 카피사용자
    var vCopyTrgtUserId = "";   // 카피 대상사용자
    var vPrivGrpId = ""; // 권한그룹ID

    // ds_privilegeCopy.AddRow();
    ds_privilegeCopy.setEmptyValue();

    vCopyTrgtUserId = ds_315List.getCellData(ds_315List.rowPosition, "userId");

    if (vCopyTrgtUserId.trim() == "") {
        $c.win.alert("권한을 복사할  대상을 선택해주십시오.");
        return false;
    }

    var vPrivReserveYn = privReserveYn.getValue();  // 기존권한유지여부
    var vPrivReserveStatus = "0";

    var vConfirmText = "권한복사를 할 경우 이전 권한은 삭제됩니다. 권한복사를 계속 진행하시겠습니까?";

    if (pType != "user" && vPrivReserveYn == true) {
        vConfirmText = "기존 사용자권한은 유지되고 추가되는 권한만 복사됩니다. 계속 진행하시겠습니까?";
        vPrivReserveStatus = "1";
    }
    var vConfirm = await $c.win.confirm(vConfirmText);

    if (vConfirm) {
        if (pType == "user") {
            // 개인권한복사
            vUserId = ed_reqId.getValue();
            if (vUserId.trim() == "") {
                $c.win.alert("권한복사 사용자를 정확하게 선택해 주십시오.");
                lux_privUser.focus();
                return false;
            }
            ds_privilegeCopy.set("userId", vUserId);
            ds_privilegeCopy.set("copyTrgtUserId", vCopyTrgtUserId);

        } else {
            // 권한그룹복사

            vPrivGrpId = lux_privGroup.getValue();
            if (vPrivGrpId.trim() == "") {
                $c.win.alert("권한복사 사용자를 정확하게 선택해 주십시오.");
                lux_privGroup.focus();
                return false;
            }
            ds_privilegeCopy.set("privGrpId", vPrivGrpId);
            ds_privilegeCopy.set("copyTrgtUserId", vCopyTrgtUserId);
            ds_privilegeCopy.set("privReserveYn", vPrivReserveStatus);
        }

        // tr_privilegeCopy.Action = "/cm.bc.comnmgnt.privmgnt.CreatePrivilegeCopyCMD.do";
        sbm_privilegeCopy.action = "/cm.bc.comnmgnt.privmgnt.CreatePrivilegeCopyCMD.do";
        $c.sbm.execute(sbm_privilegeCopy) // tr_privilegeCopy.Post();
    }
}



//-------------------------------------------------------------------------
// function name : f_privSearch()
// function desc : 권한그룹조회
//-------------------------------------------------------------------------

scwin.f_privSearch = function () {
    var privCount = ds_412List.getTotalRow();
    var usrCount = ds_315List.getTotalRow();
    if (privCount == 0 && usrCount != 0) {
        var condition = "?";
        var privGrpId = lux_privGroup.getValue();
        condition += "privilegeGroupId=" + privGrpId;

        sbm_retrieve.action = "/cm.bc.comnmgnt.privmgnt.RetrievePrivilegeGroupEachProgramPrivilegeListCMD.do" + condition;
        $c.sbm.execute(sbm_retrieve); // ds_retrieve.Reset();

    } else if (privCount == 0) {
        $c.win.alert(scwin.MSG_CM_ERR_005);
        return;
    } else if (usrCount != 0) {
        $c.win.alert(scwin.MSG_CM_ERR_004);
        return;
    }
}

//-------------------------------------------------------------------------
// function name : f_userSearch()
// function desc : 개인별권한조회
//-------------------------------------------------------------------------

scwin.f_userSearch = function () {
    var privCount = ds_412List.getTotalRow();
    var usrCount = ds_315List.getTotalRow();
    if (privCount == 0 && usrCount != 0) {
        var condition = "?";
        condition += "userId=" + userId;

        sbm_retrieve.action = "/cm.bc.comnmgnt.privmgnt.RetrieveUserEachScreenPrivilegeListCMD.do" + condition;
        $c.sbm.execute(sbm_retrieve); // ds_retrieve.Reset();

    } else if (privCount == 0) {
        $c.win.alert(scwin.MSG_CM_ERR_005);
        return;
    } else if (usrCount != 0) {
        $c.win.alert(scwin.MSG_CM_ERR_004);
        return;
    }
}



