// to-do
//-------------------------------------------------------------------------
// 거래처정보 팝업
//-------------------------------------------------------------------------
scwin.f_openClntInfoPopUp = async function (pRow) {
    var rtnList = new Array();
    udc_tplPrivilege.setSelectId("retrieveClntList");
    rtnList = await udc_tplPrivilege.cfCommonPopUp(
        scwin.f_openClntInfoPopUp_callback, '', '', "T",
        null, null, "150,180", "3,4,5,6,7,8,9,10",
        null, null, null, null, null, null, null, null, null);
}

scwin.f_openClntInfoPopUp_callback = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return false;
        let pRow = ds_tplPrivilege.rowPosition
        ds_tplPrivilege.setCellData(pRow, "clntNo", rtnList[0]);	//거래처번호
        ds_tplPrivilege.setCellData(pRow, "clntNm", rtnList[1]);	//거래처명
    }
}


// to-do
//-------------------------------------------------------------------------
// 귀속부서 팝업
//-------------------------------------------------------------------------
scwin.f_openAcctDeptCdInfoPopUp = function (pRow) {
    var rtnList = new Array();
    rtnList = cfCommonPopUp(
        'retrieveAcctDeptCdInfo', '', '', "T"
        , null, null, null, "3,4,5,6,7,8,9,10"
        , null, null, null, null, null, null, null, null, null);
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return false;

        ds_412List.setCellData(pRow, "deptCd", rtnList[0]);	//귀속부서코드
        ds_412List.setCellData(pRow, "deptNm", rtnList[1]);	//귀속부서명
    }
}



//-------------------------------------------------------------------------
// 3자물류거래처 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    var vUserId = ds_315List.getCellData(ds_315List.getRowPosition(), "userId");
    if (vUserId.trim() != "") {
        var rowIndex = ds_tplPrivilege.getTotalRow();
        ds_tplPrivilege.insertRow(rowIndex);
        ds_tplPrivilege.setCellData(rowIndex, "userId", vUserId)
        gr_tplPrivilege.setFocusedCell(rowIndex, 0);
    } else {
        $c.win.alert("3자물류거래처 추가를 위한 사용자를 선택하십시오.");
        return false;
    }
}


