//-------------------------------------------------------------------------
// 그리드 컬럼헤더 체크 변경
//-------------------------------------------------------------------------
scwin.f_GridColHeaderCheckChange = async function (pGridId) {
    // var vGridId = eval(pGridId);
    var vGridId = $p.getComponentById(pGridId)

