// to-do
// for=gr_412List event=OnHeadCheckClick(Col,Colid,bCheck)
scwin.gr_412List_onheaderclick = function (headerId) {

    // chk_header
    let bCheck = gr_412List.getHeaderValue(headerId)
    var chk;

    // var chk = bCheck == 1 ? "1" : "0";
    if (bCheck == true) {
        chk = 1;
        bCheck = 1;
    } else {
        chk = 0;
        bCheck = 0;
    }

    let headerIndex = gr_412List.getHeaderIndex(headerId)
    let Colid = gr_412List.getHeaderID(headerIndex)

    let rowStatusVal;

    // rowStatusVal = ds_412List.getRowStatusValue(0);

    // var chk = bCheck == 1 ? "T" : "F";
    // var chk = bCheck == 1 ? "1" : "0";

    var cr = ds_412List.getTotalRow();
    if (cr > 0) {
        if (Colid == "chk_header") {
            for (var i = 0; i < cr; i++) {
                // 상태표시가 x 라면 체크가 해제됨. 

                rowStatusVal = ds_412List.getRowStatusValue(i);

                if (rowStatusVal == 1) {
                    // ds_412List.setCellData(i, "chk", chk);
                } else if (rowStatusVal == 3) {
                    ds_412List.setCellData(i, "chk", 0);
                }
            }
        } else if (Colid == "insYn_header") {
            for (var i = 0; i < cr; i++) {
                ds_412List.setCellData(i, "insYn", bCheck);
            }
        } else if (Colid == "qryYn_header") {
            for (var i = 0; i < cr; i++) {
                ds_412List.setCellData(i, "qryYn", bCheck);
            }
        } else if (Colid == "modYn_header") {
            for (var i = 0; i < cr; i++) {
                ds_412List.setCellData(i, "modYn", bCheck);
            }
        } else if (Colid == "delYn_header") {
            for (var i = 0; i < cr; i++) {
                ds_412List.setCellData(i, "delYn", bCheck);
            }
        } else if (Colid == "prtnYn_header") {
            for (var i = 0; i < cr; i++) {
                ds_412List.setCellData(i, "prtnYn", bCheck);
            }
        } else if (Colid == "xlsDwnldYn_header") {
            for (var i = 0; i < cr; i++) {
                ds_412List.setCellData(i, "xlsDwnldYn", bCheck);
            }
        }
    }
};



