scwin.ds_412List_onbeforecelldatachange = function (info) {
    if (scwin._bulk) return;         // 버튼 처리 중엔 예외
    // if (info.colID !== "chk") return;

    let rowIndex = info.rowIndex;
    let rowStatus = ds_412List.getRowStatusValue(rowIndex)

    if (rowStatus == 3) {
        return false;
    }
};


//-------------------------------------------------------------------------
// function name : f_DeleteAll
// function desc : 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteAll = function () {
    scwin._bulk = true;
    try {
        var rowCnt = ds_412List.getTotalRow();
        for (var i = rowCnt - 1; i >= 0; i--) {
            ds_412List.setCellData(i, "chk", "0");
            ds_412List.deleteRow(i);
        }
    } finally {
        scwin._bulk = false;
    }
}
